template <typename T, int EPT, int FD, bool BLOCK_STRIDED>
static void launch_bench_kernel(int iters, T seed, T* ptr, dim3 grid, dim3 block) {
    switch (iters) {
#define LAUNCH_CASE(I) case I: benchmark_func<I, EPT, FD, BLOCK_STRIDED, T><<<grid, block>>>(seed, ptr); break;
        ITER_LIST(LAUNCH_CASE)
#undef LAUNCH_CASE
        default: break;
    }
}

template <typename LaunchFn>
static double time_kernel_ms(LaunchFn&& fn) {
    constexpr int total_bench_iterations = 3;
    double total = 0.0;
    for (int i = 0; i < total_bench_iterations; i++) {
        cudaEvent_t ev_start, ev_stop;
        CUDA_SAFE_CALL(cudaEventCreate(&ev_start));
        CUDA_SAFE_CALL(cudaEventCreate(&ev_stop));
        CUDA_SAFE_CALL(cudaEventRecord(ev_start));
        fn();
        CUDA_SAFE_CALL(cudaEventRecord(ev_stop));
        CUDA_SAFE_CALL(cudaEventSynchronize(ev_stop));
        float ms = 0.0f;
        CUDA_SAFE_CALL(cudaEventElapsedTime(&ms, ev_start, ev_stop));
        CUDA_SAFE_CALL(cudaEventDestroy(ev_start));
        CUDA_SAFE_CALL(cudaEventDestroy(ev_stop));
        CUDA_SAFE_CALL(cudaGetLastError());
        total += (double)ms;
    }
    return total / (double)total_bench_iterations;
}

static void runbench_warmup(short* d_ptr, long size, size_t workgroupsize) {
    const long reduced_grid_size = size / 256;
    dim3 block((unsigned int)workgroupsize);
    dim3 grid((unsigned int)(reduced_grid_size / (long)workgroupsize));
    const short seed = 1;
    launch_bench_kernel<short, 1, 1, false>(0, seed, d_ptr, grid, block);
    CUDA_SAFE_CALL(cudaDeviceSynchronize());
}

static void runbench(const int compute_iterations[],
                     unsigned int krn_idx,
                     double* d_buffer,
                     long size,
                     size_t workgroupsize,
                     unsigned int elements_per_wi,
                     unsigned int fusion_degree,
                     bool enable_dp,
                     bool enable_hp) {
    const long compute_grid_size = size / (long)elements_per_wi / (long)fusion_degree;
    const int current_compute_iterations = compute_iterations[krn_idx];
    const long long computations =
        (elements_per_wi * (long long)compute_grid_size +
         (2 * elements_per_wi * current_compute_iterations) * (long long)compute_grid_size) *
        fusion_degree;
    const long long memoryoperations = size;

    dim3 block((unsigned int)workgroupsize);
    dim3 grid((unsigned int)(compute_grid_size / (long)workgroupsize));

    double kernel_time_mad_sp = time_kernel_ms([&]() {
        float* ptr = reinterpret_cast<float*>(d_buffer);
        const float seed_f = 1.0f;
        launch_bench_kernel<float, 8, 4, false>(current_compute_iterations, seed_f, ptr, grid, block);
    });

    double kernel_time_mad_dp = 0.0;
    if (enable_dp) {
        kernel_time_mad_dp = time_kernel_ms([&]() {
            double* ptr = reinterpret_cast<double*>(d_buffer);
            const double seed_d = 1.0;
            launch_bench_kernel<double, 8, 4, false>(current_compute_iterations, seed_d, ptr, grid, block);
        });
    }

    double kernel_time_mad_hp = 0.0;
    if (enable_hp) {
        kernel_time_mad_hp = time_kernel_ms([&]() {
            __half2* ptr = reinterpret_cast<__half2*>(d_buffer);
            const __half2 seed_h = __float2half2_rn(1.0f);
            launch_bench_kernel<__half2, 8, 4, false>(current_compute_iterations, seed_h, ptr, grid, block);
        });
    }

    double kernel_time_mad_int = time_kernel_ms([&]() {
        int* ptr = reinterpret_cast<int*>(d_buffer);
        const int seed_i = 1;
        launch_bench_kernel<int, 8, 4, false>(current_compute_iterations, seed_i, ptr, grid, block);
    });

    printf(
        "         %4d,   %8.3f,%8.2f,%8.2f,%7.2f,   %8.3f,%8.2f,%8.2f,%7.2f,   "
        "%8.3f,%8.2f,%8.2f,%7.2f,  %8.3f,%8.2f,%8.2f,%7.2f\n",
        current_compute_iterations,
        ((double)computations) / ((double)memoryoperations * sizeof(float)),
        kernel_time_mad_sp,
        ((double)computations) / kernel_time_mad_sp * 1000. / (double)(1000 * 1000 * 1000),
        ((double)memoryoperations * sizeof(float)) / kernel_time_mad_sp * 1000. / (1000. * 1000. * 1000.),
        ((double)computations) / ((double)memoryoperations * sizeof(double)),
        kernel_time_mad_dp,
        ((double)computations) / kernel_time_mad_dp * 1000. / (double)(1000 * 1000 * 1000),
        ((double)memoryoperations * sizeof(double)) / kernel_time_mad_dp * 1000. / (1000. * 1000. * 1000.),
        ((double)2 * computations) / ((double)memoryoperations * sizeof(__half2)),
        kernel_time_mad_hp,
        ((double)2 * computations) / kernel_time_mad_hp * 1000. / (double)(1000 * 1000 * 1000),
        ((double)memoryoperations * sizeof(__half2)) / kernel_time_mad_hp * 1000. / (1000. * 1000. * 1000.),
        ((double)computations) / ((double)memoryoperations * sizeof(int)),
        kernel_time_mad_int,
        ((double)computations) / kernel_time_mad_int * 1000. / (double)(1000 * 1000 * 1000),
        ((double)memoryoperations * sizeof(int)) / kernel_time_mad_int * 1000. / (1000. * 1000. * 1000.));
}

extern "C" void mixbenchGPU(double* c, long size) {
    const bool block_strided = false;
    const size_t workgroupsize = 256;
    const unsigned int elements_per_wi = 8;
    const unsigned int fusion_degree = 4;

    printf("Workitem stride:        %s\n", block_strided ? "Workgroup" : "NDRange");
    printf("Buffer allocation:      Device allocated\n");
    printf("Timer:                  CL event based\n");

    int major = 0, minor = 0;
    int dev = 0;
    CUDA_SAFE_CALL(cudaGetDevice(&dev));
    CUDA_SAFE_CALL(cudaDeviceGetAttribute(&major, cudaDevAttrComputeCapabilityMajor, dev));
    CUDA_SAFE_CALL(cudaDeviceGetAttribute(&minor, cudaDevAttrComputeCapabilityMinor, dev));

    bool enable_dp = (major > 1) || (major == 1 && minor >= 3);
    if (!enable_dp)
        printf("Warning:                Double precision computations are not supported\n");

    bool enable_hp = IsFP16Supported();
    if (!enable_hp)
        printf("Warning:                Half precision computations are not supported\n");

    double* d_buffer = nullptr;
    CUDA_SAFE_CALL(cudaMalloc((void**)&d_buffer, (size_t)size * sizeof(double)));
    CUDA_SAFE_CALL(cudaMemset(d_buffer, 0, (size_t)size * sizeof(double)));

    runbench_warmup(reinterpret_cast<short*>(d_buffer), size, workgroupsize);

    printf(
        "----------------------------------------------------------------------------- CSV data "
        "-----------------------------------------------------------------------------"
        "-----\n");
    printf(
        "Experiment ID, Single Precision ops,,,,              Double precision "
        "ops,,,,              Half precision ops,,,,                Integer "
        "operations,,, \n");
    printf(
        "Compute iters, Flops/byte, ex.time,  GFLOPS, GB/sec, Flops/byte, "
        "ex.time,  GFLOPS, GB/sec, Flops/byte, ex.time,  GFLOPS, GB/sec, "
        "Iops/byte, ex.time,   GIOPS, GB/sec\n");

    for (int i = 0; i < compute_iterations_len; i++) {
        runbench(compute_iterations, i, d_buffer, size, workgroupsize, elements_per_wi, fusion_degree, enable_dp, enable_hp);
    }

    printf(
        "------------------------------------------------------------------------------------------------"
        "--------------------------------------------------------"
        "--------------------\n");

    CUDA_SAFE_CALL(cudaMemcpy(c, d_buffer, (size_t)size * sizeof(double), cudaMemcpyDeviceToHost));
    CUDA_SAFE_CALL(cudaFree(d_buffer));
}
